(function(){
  var frame  = document.getElementById('pybot-first-light');
  var status = document.getElementById('pybot-status-first-light');
  var medalEl = document.getElementById('pybot-medal-first-light');
  var levelString = `Gold: 5
Silver: 7
Bronze: 10
Dir: 0

Height map:
11111

Item map:
P000L`;
  var starterCode = "";
  var completed = false;

  function sendLevel() {
    frame.contentWindow.postMessage({ type: 'LOAD_CUSTOM_LEVEL', data: { levelString: levelString } }, '*');
    if (starterCode) {
      setTimeout(function() {
        frame.contentWindow.postMessage({ type: 'SET_CODE', data: { code: starterCode } }, '*');
      }, 500);
    }
  }

  frame.addEventListener('load', function() {
    sendLevel();
  });

  window.addEventListener('message', function(e) {
    if (e.source !== frame.contentWindow) return;
    if (e.data.type === 'LEVEL_LOADED') {
      status.innerHTML = '<span class="text-sm text-green-700 font-medium">&#x2705; Level ready &#x2014; write your code and press Play!</span>';
    }
    if (e.data.type === 'LEVEL_COMPLETE') {
      var medal = e.data.medal || '';
      medalEl.textContent = medal;
      medalEl.classList.remove('hidden');
      status.innerHTML = '<span class="text-sm text-green-700 font-bold">&#x1F389; Level complete! ' + medal + ' &#x2014; ' + e.data.lines + ' lines in ' + Math.round(e.data.time) + 's</span>';
      if (!completed) {
        completed = true;
        window.__markStepComplete && window.__markStepComplete();
      }
    }
  });

  frame.src = 'https://jquinney-hue.github.io/PyBot?hideMenu=true';
})();

