(function(){
  var challenges = [
  {
    "title": "Straight line, 3 steps",
    "hint": "Walk forward 3 times then light().",
    "levelString": "Gold: 2\nSilver: 4\nBronze: 6\nDir: 0\n\nHeight map:\n1111\n\nItem map:\nP00L",
    "starter": ""
  },
  {
    "title": "Straight line, 6 steps",
    "hint": "Use range(6) in a for loop.",
    "levelString": "Gold: 3\nSilver: 5\nBronze: 8\nDir: 0\n\nHeight map:\n1111111\n\nItem map:\nP00000L",
    "starter": "# Use range(6) in a for loop\n"
  },
  {
    "title": "Two lights in a row",
    "hint": "Walk, light, walk, light.",
    "levelString": "Gold: 4\nSilver: 6\nBronze: 9\nDir: 0\n\nHeight map:\n11111\n\nItem map:\nP0L0L",
    "starter": ""
  },
  {
    "title": "L-shape (2 steps each side)",
    "hint": "Walk 2, turn right, walk 2, light.",
    "levelString": "Gold: 5\nSilver: 8\nBronze: 12\nDir: 0\n\nHeight map:\n111\n111\n111\n\nItem map:\nP00\n000\n00L",
    "starter": ""
  },
  {
    "title": "L-shape (3+2 steps)",
    "hint": "Walk 3 right, turn right, walk 2 down, light.",
    "levelString": "Gold: 6\nSilver: 9\nBronze: 13\nDir: 0\n\nHeight map:\n1111\n1111\n1111\n\nItem map:\nP000\n0000\n000L",
    "starter": ""
  },
  {
    "title": "Square — 2 steps per side",
    "hint": "Loop 3 times: walk 2, light, turn right.",
    "levelString": "Gold: 4\nSilver: 6\nBronze: 10\nDir: 0\n\nHeight map:\n111\n101\n111\n\nItem map:\nP0L\n000\nL0L",
    "starter": "# Loop 3 times: walk 2, light, turn right\n"
  },
  {
    "title": "Square — 4 steps per side",
    "hint": "Outer loop 3 times, inner loop 4 times.",
    "levelString": "Gold: 4\nSilver: 6\nBronze: 9\nDir: 0\n\nHeight map:\n11111\n10001\n10001\n10001\n11111\n\nItem map:\nP000L\n00000\n00000\n00000\nL000L",
    "starter": "# Outer loop 3 times\n# Inner loop - how many steps?\n"
  },
  {
    "title": "All 4 corners — 3×3 grid",
    "hint": "Light start, then loop 4 times: walk 2, light, turn right.",
    "levelString": "Gold: 5\nSilver: 8\nBronze: 12\nDir: 0\n\nHeight map:\n111\n101\n111\n\nItem map:\nL0L\n000\nP0L",
    "starter": "# Light the start, then loop 4 times\n"
  },
  {
    "title": "All 4 corners — 4×4 grid",
    "hint": "Loop 4 times: walk 3, light, turn right. Light the start too!",
    "levelString": "Gold: 6\nSilver: 9\nBronze: 13\nDir: 3\n\nHeight map:\n1111\n1001\n1001\n1111\n\nItem map:\nL00L\n0000\n0000\nL00L",
    "starter": "# How many steps per side?\n"
  },
  {
    "title": "All 4 corners — 6×6 grid",
    "hint": "Each side has 5 steps. Loop 4 times.",
    "levelString": "Gold: 6\nSilver: 9\nBronze: 13\nDir: 0\n\nHeight map:\n111111\n100001\n100001\n100001\n100001\n111111\n\nItem map:\nL0000L\n000000\n000000\n000000\n000000\nP000L0",
    "starter": "# How many steps on each side of a 6x6 grid?\n"
  }
];
  var currentIdx = -1;
  var streak = 0;
  var best = parseInt(localStorage.getItem('pylearn_pybot_best') || '0', 10);
  document.getElementById('el-best').textContent = best;

  function loadChallenge(idx) {
    var ch = challenges[idx];
    var frame  = document.getElementById('pybot-endless');
    var status = document.getElementById('pybot-status-endless');
    document.getElementById('el-title').textContent = ch.title;
    document.getElementById('el-hint').textContent = '\u1F4A1 ' + ch.hint;
    status.textContent = 'Loading\u2026';

    // Remove old listener to avoid duplicates
    if (window.__pybotEndlessListener) {
      window.removeEventListener('message', window.__pybotEndlessListener);
    }

    function onMessage(e) {
      if (e.source !== frame.contentWindow) return;
      if (e.data.type === 'LEVEL_LOADED') {
        status.textContent = '\u2705 Level ready \u2014 write your code and press Play!';
        if (ch.starter) {
          frame.contentWindow.postMessage({ type: 'SET_CODE', data: { code: ch.starter } }, '*');
        }
      }
      if (e.data.type === 'LEVEL_COMPLETE') {
        streak++;
        status.innerHTML = '<span class="text-green-700 font-bold">\u1F389 Complete! ' + (e.data.medal||'') + ' \u2014 ' + e.data.lines + ' lines in ' + Math.round(e.data.time) + 's</span>';
        if (streak > best) {
          best = streak;
          localStorage.setItem('pylearn_pybot_best', best);
          document.getElementById('el-best').textContent = best;
        }
        document.getElementById('el-streak').textContent = streak;
        setTimeout(function() {
          var next = (idx + 1) % challenges.length;
          loadChallenge(next);
        }, 2500);
      }
    }
    window.__pybotEndlessListener = onMessage;
    window.addEventListener('message', onMessage);

    function doLoad() {
      frame.contentWindow.postMessage({ type: 'LOAD_CUSTOM_LEVEL', data: { levelString: ch.levelString } }, '*');
    }
    if (frame.contentDocument && frame.contentDocument.readyState === 'complete' && frame.src !== 'about:blank') {
      doLoad();
    } else {
      frame.onload = doLoad;
      if (!frame.src || frame.src === 'about:blank' || frame.src === window.location.href) {
        frame.src = 'https://jquinney-hue.github.io/PyBot?hideMenu=true';
      } else {
        frame.contentWindow.postMessage({ type: 'LOAD_CUSTOM_LEVEL', data: { levelString: ch.levelString } }, '*');
        if (ch.starter) {
          setTimeout(function() {
            frame.contentWindow.postMessage({ type: 'SET_CODE', data: { code: ch.starter } }, '*');
          }, 800);
        }
      }
    }
  }

  document.getElementById('el-skip').onclick = function() {
    streak = 0;
    document.getElementById('el-streak').textContent = streak;
    currentIdx = (currentIdx + 1) % challenges.length;
    loadChallenge(currentIdx);
  };

  currentIdx = 0;
  var frame = document.getElementById('pybot-endless');
  frame.onload = function() { loadChallenge(0); };
  frame.src = 'https://jquinney-hue.github.io/PyBot?hideMenu=true';
})();
